var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이상하군. 분명 여기 있어야 할 텐데…….","JPN":"おかしいな。確かにここにあるはずだが……","ENG":"I don't get it. They have to have been here...","TWN":"奇怪，怎麼不在這裡……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흠흐흠~♪ 얼른 빨래 하고 축구 보러 가야지~♪","JPN":"フンフフ～ン♪　早く洗濯して、サッカー観に行こうっと～♪","ENG":"La, la, la. ♪ Let's finish doing laundry and go watch football! ♪","TWN":"哼哼哼～♪ 趕快洗完衣服來去看足球～♪"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어라? 세탁실에 무슨 일이야, 단장?","JPN":"あれ、団長？　洗濯室には何の用？","ENG":"Err? Captain? What are you doing in the laundry room?","TWN":"嗯？團長，你在洗衣間裡幹嘛？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"리, 리브 경? 설마 날 미행한 건가?","JPN":"り、リブ卿？　まさか後をつけていたのか？","ENG":"D-Dame Liv! Oh no, did you follow me?","TWN":"莉…莉芙卿？你該不會是跟蹤我吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"헤헤, 그럴 리가. 훈련 받고 났더니 운동복이 흙투성이가 됐거든.","JPN":"えへへ、まさか。　訓練してたら服が泥だらけになっちゃって。","ENG":"Heh heh. No way. My tracksuit got all muddy after training.","TWN":"嘿嘿，怎麼可能～是因為訓練完後，運動服整個髒兮兮的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장은 하루가 다르게 더 엄격해지는 거 같다니까.","JPN":"副団長って日に日に厳しくなってる気がするんだよね。","ENG":"The Deputy is becoming sterner by the day.","TWN":"還不是因為副團長一天比一天更嚴格！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오늘은 공룡 운동복 입고 훈련 나왔다고 기강이 해이해졌다면서 구박하는 거 있지?","JPN":"今日は恐竜のジャージで訓練に出たら、たるんでるって怒られたの。","ENG":"I came to training with a dinosaur tracksuit today, and she was so hard on me, saying that discipline got lax.","TWN":"因為我今天穿著恐龍運動服去訓練，她就說我目無法紀，然後折磨我！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"공룡……?","JPN":"恐竜……？","ENG":"Dinosaur...?","TWN":"恐龍……？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응. 심지어 그냥 공룡도 아니고 메카 티라노사우르스였다구.","JPN":"うん、それもメカ・ティラノサウルス！","ENG":"Yes. It wasn't just an ordinary dinosaur, either. It was a Mech T-Rex.","TWN":"對啊！而且它可不普通的恐龍，是暴龍欸！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스랑 한솔이도 귀엽다고 칭찬해 줬어!","JPN":"アリウスとイチロウもかわいいって褒めてくれたんだ。","ENG":"Arius and Hansol told me that it was cute.","TWN":"埃里奧斯和楊瀚也都說很可愛的！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으으……. 부단장이 훈련 중에 빵 터지는 모습을 보고 싶어서 잔뜩 기합 넣었는데.","JPN":"ううっ……訓練中に副団長が吹き出すところが見たくて、気合入れて用意したのに。","ENG":"Gah! I wore it to make the Deputy crack up during our training.","TWN":"哼……我為了要看副團長爆笑的表情，費了多大的力氣啊！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크흠. 그런 복장은 훈련 중에 움직이기 불편해서 지적한 것 아니겠나?","JPN":"コホン……そんな服装は動きづらいから指摘したんじゃないのか？","ENG":"Hm... She was probably unhappy with you because such clothes can hinder your movement during training.","TWN":"咳咳，會不會是因為穿那種衣服不方便訓練，副團長才責備你的？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"단순히 아이들 잠옷처럼 귀엽게 생겼다고 꾸짖지는 않았을 거다.","JPN":"単に、子どものパジャマのような見た目だからという理由で怒ったわけではないだろう。","ENG":"She couldn't have punished you because your clothes looked like children's pajamas.","TWN":"應該不至於因為衣服長得跟睡衣一樣可愛就罵人吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"절대 아니야! 부단장이 눈을 이렇게 사납게 뜨고 그랬는걸?","JPN":"それは絶対違う！　副団長、こんな感じできつく睨んで言ったんだよ！","ENG":"Yes, she did! The Deputy glared at me and said,","TWN":"才不是咧！副團長的眼神這麼兇狠欸？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>평기사 분들도 보시는데 무슨 그런 유치한 복장을! 조디악 나이츠의 이름에 먹칠을 할 셈입니까?</color>","JPN":"<color=#ffd34c>平騎士の皆さんも見ているのにそんな幼稚な服装で来るとは！　ゾディアックナイツの名に泥を塗るつもりですか！</color>","ENG":"<color=#ffd34c>How can you show up in such childish attire before the knight bachelors? Are you trying to embarrass the Zodiac Knights?</color>","TWN":"<color=#ffd34c>平民騎士也都在看，你穿這是什麼幼稚的服裝！你是想害十二宮騎士團的名譽掃地嗎？</color>"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으, 누가 전갈 아니랄까 봐.","JPN":"ううっ、やっぱりサソリは怖い。","ENG":"Hmpf, that scorpion.","TWN":"哼，怕人家不知道她是天蠍嗎！"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"공룡도 안 되는 건가……? 그렇다면 나는 어떻게 해야……?","JPN":"恐竜も駄目なのか……？　それなら私はどうすれば……？","ENG":"So, she doesn't like dinosaurs, either. Then... what do I do...?","TWN":"恐龍也不行嗎……？那我該怎麼……？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 단장, 아까 봤는데 여기서 뭐 찾고 있었어?","JPN":"ところで団長はここで何か探してるの？","ENG":"By the way, Captain, are you looking for something here?","TWN":"不過團長，我剛有看到，你是在找什麼東西嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그건…….","JPN":"あっ、それは……","ENG":"Ah, that's...","TWN":"喔，那個……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};